class ChatHistory:
    def __init__(self, max_tokens=4000):
        self.messages = []
        self.max_tokens = max_tokens

    def add_system(self, content):
        self.messages.append({'role': '___', 'content': content})

    def add_user(self, content):
        self.messages.append({'role': '___', 'content': content})

    def add_assistant(self, content):
        self.messages.append({'role': '___', 'content': content})

    def estimate_tokens(self):
        return sum(len(m['content']) // 4 for m in self.messages)

    def get_messages(self):
        # Trim old messages if over limit (keep system + recent)
        while self.estimate_tokens() > self.max_tokens and len(self.messages) > 2:
            self.messages.pop(1)  # Remove oldest non-system message
        return self.messages

    def display(self):
        for m in self.messages:
            print(f"[{m['role']}]: {m['content'][:50]}...")

chat = ChatHistory(max_tokens=100)
chat.add_system('You are a helpful tutor.')
chat.add_user('What is Python?')
chat.add_assistant('Python is a high-level programming language.')
chat.add_user('How do I learn it?')
